              {
                "type": "Script",
                "source": "if (!this.initialized) {\n  this.timer = 0;\n  this.tickRate = 0.15;\n  this.gridSize = 32;\n  this.dir = {x: 1, y: 0};\n  this.nextDir = {x: 1, y: 0};\n  this.tailPos = [];\n  this.length = 3;\n  this.initialized = true;\n  if (this.entity.body) this.entity.body.type = 'static';\n}\n\nconst up = Input.keys && Input.keys['ArrowUp'];\nconst down = Input.keys && Input.keys['ArrowDown'];\nconst left = Input.keys && Input.keys['ArrowLeft'];\nconst right = Input.keys && Input.keys['ArrowRight'];\n\nif (up && this.dir.y === 0) this.nextDir = {x: 0, y: -1};\nif (down && this.dir.y === 0) this.nextDir = {x: 0, y: 1};\nif (left && this.dir.x === 0) this.nextDir = {x: -1, y: 0};\nif (right && this.dir.x === 0) this.nextDir = {x: 1, y: 0};\n\nthis.timer += Time.deltaTime || 0.016;\n\nif (this.timer >= this.tickRate) {\n  this.timer = 0;\n  this.dir = this.nextDir;\n\n  this.tailPos.unshift({x: this.entity.transform.x, y: this.entity.transform.y});\n  if (this.tailPos.length > this.length) {\n    this.tailPos.pop();\n  }\n\n  this.entity.transform.x += this.dir.x * this.gridSize;\n  this.entity.transform.y += this.dir.y * this.gridSize;\n\n  let food = scene.entities.find(e => e.name === 'Food');\n  if (food) {\n    let dx = Math.abs(this.entity.transform.x - food.transform.x);\n    let dy = Math.abs(this.entity.transform.y - food.transform.y);\n    if (dx < 10 && dy < 10) {\n      this.length++;\n      food.transform.x = Math.floor(Math.random() * 17 + 1) * this.gridSize;\n      food.transform.y = Math.floor(Math.random() * 17 + 1) * this.gridSize;\n    }\n  }\n\n  for(let i=0; i<15; i++) {\n    let t = scene.entities.find(e => e.name === 'Tail' + i);\n    if (t) {\n      if (i < this.tailPos.length) {\n        t.transform.x = this.tailPos[i].x;\n        t.transform.y = this.tailPos[i].y;\n      } else {\n        t.transform.x = -1000;\n      }\n    }\n  }\n\n  let dead = false;\n  if (this.entity.transform.x < 32 || this.entity.transform.x > 576 ||\n      this.entity.transform.y < 32 || this.entity.transform.y > 576) {\n    dead = true;\n  }\n  for(let i=0; i<this.tailPos.length; i++) {\n    if (this.entity.transform.x === this.tailPos[i].x &&\n        this.entity.transform.y === this.tailPos[i].y) {\n      dead = true;\n    }\n  }\n\n  if (dead) {\n    this.entity.transform.x = 320;\n    this.entity.transform.y = 320;\n    this.length = 3;\n    this.tailPos = [];\n    this.dir = {x: 1, y: 0};\n    this.nextDir = {x: 1, y: 0};\n  }\n}"
              }
